import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import { X, MapPin, Navigation, Store } from 'lucide-react';
import L from 'leaflet';

// Configuramos el icono de "Negocio" profesional
const iconoNegocio = new L.Icon({
  iconUrl: 'https://cdn-icons-png.flaticon.com/512/606/606161.png', // Icono de tienda
  iconSize: [38, 38],
  iconAnchor: [19, 38],
  popupAnchor: [0, -38],
});

function LocationPicker({ position, setPosition, onAddressFound }) {
  useMapEvents({
    async click(e) {
      const { lat, lng } = e.latlng;
      setPosition([lat, lng]);
      
      try {
        const response = await fetch(
          `https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${lat}&lon=${lng}`
        );
        const data = await response.json();
        if (data.address) {
          onAddressFound(data.address);
        }
      } catch (error) {
        console.error("Error buscando la dirección", error);
      }
    }
  });

  // Usamos el icono de negocio aquí
  return position ? <Marker position={position} icon={iconoNegocio} /> : null;
}

const ModalNuevaSucursal = ({ onClose, onSave }) => {
  const [nombre, setNombre] = useState('');
  const [direccion, setDireccion] = useState('');
  const [provincia, setProvincia] = useState('');
  const [ciudad, setCiudad] = useState('');
  const [coords, setCoords] = useState([-26.816, -65.216]);

  const handleAddressFound = (address) => {
    const calle = address.road || '';
    const numero = address.house_number || '';
    setDireccion(`${calle} ${numero}`.trim());
    setCiudad(address.city || address.town || address.village || '');
    setProvincia(address.state || '');
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!ciudad || !direccion) return alert("Por favor, marca la ubicación en el mapa");
    
    onSave({ 
      nombre, 
      direccion, 
      provincia, 
      ciudad, 
      lat: coords[0], 
      lng: coords[1] 
    });
  };

  return (
    <div style={modalOverlay}>
      <div style={modalContent}>
        <div style={headerStyle}>
          <div>
            <h3 style={{ margin: 0, color: '#1e293b', fontSize: '1.2rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
              <Store size={22} color="#e67e22" /> Nueva Sucursal
            </h3>
            <p style={{ margin: 0, fontSize: '0.8rem', color: '#64748b' }}>Ubica tu negocio en el mapa</p>
          </div>
          <button onClick={onClose} style={closeBtn}><X size={20} /></button>
        </div>

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          
          <div style={inputGroup}>
            <label style={labelStyle}>Nombre del Negocio</label>
            <input 
              placeholder="Ej: Almacén 'El Triunfo'" 
              style={inputStyle} 
              required 
              value={nombre} 
              onChange={e => setNombre(e.target.value)} 
            />
          </div>

          <div style={mapContainerStyle}>
            <MapContainer center={coords} zoom={15} style={{ height: '100%' }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              <LocationPicker 
                position={coords} 
                setPosition={setCoords} 
                onAddressFound={handleAddressFound} 
              />
            </MapContainer>
            <div style={mapOverlayBadge}>
              <Navigation size={12} /> Toca el mapa para situar el local
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
            <div style={inputGroup}>
              <label style={labelStyle}>Calle y Número</label>
              <input style={inputStyle} value={direccion} readOnly placeholder="Detectado..." />
            </div>
            <div style={inputGroup}>
              <label style={labelStyle}>Ciudad</label>
              <input style={inputStyle} value={ciudad} readOnly placeholder="Detectado..." />
            </div>
          </div>

          <button type="submit" style={btnSubmitModal}>
            <MapPin size={18} /> Confirmar Ubicación del Negocio
          </button>
        </form>
      </div>
    </div>
  );
};

/* --- ESTILOS --- */
const modalOverlay = { position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(15, 23, 42, 0.8)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 3000, backdropFilter: 'blur(8px)' };
const modalContent = { background: 'white', padding: '25px', borderRadius: '24px', width: '480px', boxShadow: '0 25px 50px -12px rgba(0,0,0,0.25)' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '20px' };
const closeBtn = { background: '#f1f5f9', border: 'none', padding: '5px', borderRadius: '8px', cursor: 'pointer', color: '#64748b' };
const inputGroup = { display: 'flex', flexDirection: 'column', gap: '5px' };
const labelStyle = { fontSize: '0.75rem', fontWeight: 'bold', color: '#475569', textTransform: 'uppercase' };
const inputStyle = { width: '100%', padding: '12px', borderRadius: '12px', border: '1px solid #e2e8f0', background: '#f8fafc', fontSize: '0.9rem', outline: 'none' };
const mapContainerStyle = { height: '220px', borderRadius: '16px', overflow: 'hidden', border: '2px solid #f1f5f9', position: 'relative' };
const mapOverlayBadge = { position: 'absolute', bottom: '10px', left: '10px', zIndex: 1000, background: 'rgba(30, 41, 59, 0.9)', color: 'white', padding: '4px 10px', borderRadius: '20px', fontSize: '0.7rem', display: 'flex', alignItems: 'center', gap: '5px' };
const btnSubmitModal = { width: '100%', padding: '16px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '14px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '10px' };

export default ModalNuevaSucursal;
